-- M135: 바로(주)/디케이 1Q 발주 데이터 → orders 추가
BEGIN;
DROP VIEW IF EXISTS outbounds_sale_unregistered;
DROP VIEW IF EXISTS outbounds_with_meta;
DROP VIEW IF EXISTS orders_with_meta;
ALTER TABLE orders ALTER COLUMN order_number TYPE varchar(60);
CREATE OR REPLACE VIEW orders_with_meta AS SELECT o.order_id,                                            
     o.order_number,                                            
     o.company_id,                                              
     o.customer_id,                                             
     o.order_date,                                              
     o.receipt_method,                                          
     o.product_id,                                              
     o.quantity,                                                
     o.capacity_kw,                                             
     o.unit_price_wp,                                           
     o.site_name,                                               
     o.site_address,                                            
     o.site_contact,                                            
     o.site_phone,                                              
     o.payment_terms,                                           
     o.deposit_rate,                                            
     o.delivery_due,                                            
     o.shipped_qty,                                             
     o.remaining_qty,                                           
     o.status,                                                  
     o.spare_qty,                                               
     o.memo,                                                    
     o.created_at,                                              
     o.updated_at,                                              
     o.management_category,                                     
     o.fulfillment_source,                                      
     o.bl_id,                                                   
     o.site_id,                                                 
     o.unit_price_ea,                                           
     o.source_payload,                                          
     p.partner_name AS customer_name,                           
     prod.product_code,                                         
     prod.product_name                                          
    FROM orders o                                               
      LEFT JOIN partners p ON p.partner_id = o.customer_id      
      LEFT JOIN products prod ON prod.product_id = o.product_id;
CREATE OR REPLACE VIEW outbounds_with_meta AS SELECT o.outbound_id,                                             
     o.outbound_date,                                               
     o.company_id,                                                  
     o.product_id,                                                  
     o.quantity,                                                    
     o.capacity_kw,                                                 
     o.warehouse_id,                                                
     o.usage_category,                                              
     o.order_id,                                                    
     o.site_name,                                                   
     o.site_address,                                                
     o.spare_qty,                                                   
     o.group_trade,                                                 
     o.target_company_id,                                           
     o.erp_outbound_no,                                             
     o.memo,                                                        
     o.created_at,                                                  
     o.updated_at,                                                  
     o.status,                                                      
     o.dispatch_route_id,                                           
     o.tx_statement_ready,                                          
     o.inspection_request_sent,                                     
     o.approval_requested,                                          
     o.tax_invoice_issued,                                          
     o.source_payload,                                              
     p.product_code,                                                
     p.product_name,                                                
     p.manufacturer_id AS product_manufacturer_id,                  
     ord.order_number,                                              
     w.warehouse_name,                                              
     tc.company_name AS target_company_name,                        
     tc.company_code AS target_company_code                         
    FROM outbounds o                                                
      LEFT JOIN products p ON p.product_id = o.product_id           
      LEFT JOIN orders ord ON ord.order_id = o.order_id             
      LEFT JOIN warehouses w ON w.warehouse_id = o.warehouse_id     
      LEFT JOIN companies tc ON tc.company_id = o.target_company_id;
CREATE OR REPLACE VIEW outbounds_sale_unregistered AS SELECT outbound_id,                                                                                                                       
     outbound_date,                                                                                                                         
     company_id,                                                                                                                            
     product_id,                                                                                                                            
     quantity,                                                                                                                              
     capacity_kw,                                                                                                                           
     warehouse_id,                                                                                                                          
     usage_category,                                                                                                                        
     order_id,                                                                                                                              
     site_name,                                                                                                                             
     site_address,                                                                                                                          
     spare_qty,                                                                                                                             
     group_trade,                                                                                                                           
     target_company_id,                                                                                                                     
     erp_outbound_no,                                                                                                                       
     memo,                                                                                                                                  
     created_at,                                                                                                                            
     updated_at,                                                                                                                            
     status,                                                                                                                                
     dispatch_route_id,                                                                                                                     
     tx_statement_ready,                                                                                                                    
     inspection_request_sent,                                                                                                               
     approval_requested,                                                                                                                    
     tax_invoice_issued,                                                                                                                    
     source_payload,                                                                                                                        
     product_code,                                                                                                                          
     product_name,                                                                                                                          
     product_manufacturer_id,                                                                                                               
     order_number,                                                                                                                          
     warehouse_name,                                                                                                                        
     target_company_name,                                                                                                                   
     target_company_code                                                                                                                    
    FROM outbounds_with_meta om                                                                                                             
   WHERE (usage_category::text = ANY (ARRAY['sale'::character varying, 'sale_spare'::character varying]::text[])) AND NOT (EXISTS ( SELECT 1
            FROM sales s                                                                                                                    
           WHERE s.outbound_id = om.outbound_id AND s.status <> 'cancelled'::text));
COMMIT;
NOTIFY pgrst, 'reload schema';
